import React, { useState } from 'react';

const questions = [
  "¿Por qué estás interesado en este puesto?",
  "¿Qué experiencia previa tienes en roles similares?",
  "¿Cómo manejas situaciones de presión o estrés en el trabajo?",
  "¿Cuál ha sido tu mayor logro profesional y por qué?",
  "¿Qué herramientas o tecnologías dominas que consideras relevantes para este puesto?",
  "¿Cómo manejas el trabajo en equipo y la colaboración?",
  "¿Dónde te ves profesionalmente en cinco años?",
  "¿Qué te motiva a dar lo mejor de ti en un empleo?"
];

function Result({ analysis, answers, onBack }) {
  const [manualScores, setManualScores] = useState(Array(8).fill(0));
  const [enviado, setEnviado] = useState(false);
  const total = manualScores.reduce((a, b) => a + b, 0);
  const resultadoFinal = total >= 12
    ? "✅ APTO para la siguiente fase."
    : "⚠️ Revisión recomendada.";

  const handleManualScore = (index, value) => {
    const newScores = [...manualScores];
    newScores[index] = parseInt(value);
    setManualScores(newScores);
  };

  const guardarEnBase = async () => {
    // Simulación de IDs (pueden venir del login o selector luego)
    const postulante_id = 1;
    const entrevistador_id = 1;

    const respuestasEvaluadas = questions.map((q, i) => ({
      pregunta_id: i + 1,
      texto: answers[i],
      evaluacion_automatica: extractEvalDePregunta(analysis, i + 1),
      puntaje_manual: manualScores[i],
      comentario_manual: "", // puedes agregar inputs por respuesta si lo deseas
    }));

    const datos = {
      postulante_id,
      entrevistador_id,
      respuestas: respuestasEvaluadas
    };

    try {
      const response = await fetch("http://localhost//sistema-entrevistas/backend/api/guardar_respuesta.php", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(datos)
      });

      const result = await response.json();
      if (result.status === "ok") {
        setEnviado(true);
        alert("✅ Evaluación guardada correctamente.");
      } else {
        alert("⚠️ Hubo un problema al guardar.");
      }
    } catch (err) {
      console.error("Error al enviar:", err);
      alert("❌ Error de conexión con el backend.");
    }
  };

  // Función para extraer una sección del análisis automático por pregunta (opcional, si analizás por pregunta)
  const extractEvalDePregunta = (analysisText, preguntaId) => {
    // Por ahora devolvemos todo el análisis como bloque
    return analysisText;
  };

  return (
    <div style={{ maxWidth: '700px', margin: '0 auto', padding: '20px' }}>
      <h2>Análisis Automático</h2>
      <div
        style={{
          backgroundColor: '#f5f5f5',
          padding: '15px',
          borderRadius: '10px',
          whiteSpace: 'pre-wrap',
          fontFamily: 'Arial, sans-serif',
          marginBottom: '30px'
        }}
      >
        {analysis}
      </div>

      <h3>📋 Respuestas del Candidato y Evaluación Manual</h3>
      {questions.map((q, i) => (
        <div key={i} style={{ marginBottom: '20px' }}>
          <strong>{q}</strong>
          <div style={{
            backgroundColor: '#f0f0f0',
            padding: '10px',
            borderRadius: '6px',
            whiteSpace: 'pre-wrap'
          }}>
            {answers[i] || '(Sin respuesta)'}
          </div>

          <label style={{ marginTop: '6px', display: 'block' }}>
            Puntuación del entrevistador (0 a 2):{" "}
            <select
              value={manualScores[i]}
              onChange={(e) => handleManualScore(i, e.target.value)}
              style={{ marginLeft: '10px' }}
            >
              <option value={0}>0</option>
              <option value={1}>1</option>
              <option value={2}>2</option>
            </select>
          </label>
        </div>
      ))}

      <hr />
      <h4>Total: {total} / 16</h4>
      <p><strong>Resultado final:</strong> {resultadoFinal}</p>

      {!enviado && (
        <button
          onClick={guardarEnBase}
          style={{
            marginTop: '10px',
            marginRight: '10px',
            padding: '10px 20px',
            backgroundColor: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            cursor: 'pointer',
          }}
        >
          Guardar evaluación
        </button>
      )}

      <button
        onClick={onBack}
        style={{
          marginTop: '10px',
          padding: '10px 20px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '8px',
          cursor: 'pointer',
        }}
      >
        Realizar otra evaluación
      </button>
    </div>
  );
}

export default Result;
